#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main(void) {
    /* Each process sees its own virtual address space */
    int x = 42;
    printf("Virtual address of x: %p\n", (void *)&x);
    /* Same virtual address in different processes
       maps to different physical frames */

    /* Page size is typically 4096 bytes */
    long page_size = sysconf(_SC_PAGESIZE);
    printf("Page size: %ld bytes\n", page_size); /* 4096 */

    /* Total physical pages */
    long phys_pages = sysconf(_SC_PHYS_PAGES);
    printf("Physical memory: %ld MB\n",
           (phys_pages * page_size) / (1024 * 1024));

    /* Allocate memory -- pages are NOT allocated until accessed */
    /* (demand paging) */
    size_t size = 100 * 1024 * 1024; /* 100 MB */
    char *p = malloc(size);
    if (!p) { perror("malloc"); return 1; }

    /* At this point, no physical pages are allocated.
       Only virtual address space is reserved. */

    /* Touching a page triggers a page fault,
       which allocates a physical frame */
    p[0] = 'A';              /* page fault -> allocate 1 page */
    p[page_size] = 'B';      /* page fault -> allocate another page */
    p[2 * page_size] = 'C';  /* page fault -> allocate another page */

    /* Only 3 physical pages used, not 100MB worth */

    free(p);
    return 0;
}

