void file_backed_mmap(void) {
    int fd = open("testfile.txt", O_RDWR | O_CREAT | O_TRUNC, 0644);
    if (fd == -1) { perror("open"); return; }

    /* Extend file to desired size */
    const size_t size = 4096;
    ftruncate(fd, size);

    /* Map the file into memory */
    char *map = mmap(NULL, size, PROT_READ | PROT_WRITE,
                     MAP_SHARED, fd, 0);
    if (map == MAP_FAILED) { perror("mmap"); close(fd); return; }

    /* Write through the mapping */
    strcpy(map, "Hello via mmap!");
    printf("Read from mapping: %s\n", map);

    /* Flush to disk */
    msync(map, size, MS_SYNC);

    munmap(map, size);
    close(fd);
}

void anonymous_mmap(void) {
    /* Allocate 1MB of zeroed memory (no file backing) */
    size_t size = 1024 * 1024;
    int *arr = mmap(NULL, size, PROT_READ | PROT_WRITE,
                    MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (arr == MAP_FAILED) { perror("mmap"); return; }

    /* Use like malloc'd memory */
    arr[0] = 42;
    printf("Anonymous mmap: arr[0] = %d\n", arr[0]);

    munmap(arr, size);
}

int main(void) {
    file_backed_mmap();
    anonymous_mmap();
    return 0;
}

