/* Demonstrate fragmentation */
int main(void) {
    /* Allocate many small blocks */
    const int N = 1000;
    char *ptrs[1000];

    for (int i = 0; i < N; i++) {
        ptrs[i] = malloc(100); /* 100 bytes each */
    }
    printf("Allocated %d blocks of 100 bytes\n", N);

    /* Free every other block -- creates external fragmentation */
    for (int i = 0; i < N; i += 2) {
        free(ptrs[i]);
        ptrs[i] = NULL;
    }
    printf("Freed every other block (external fragmentation)\n");

    /* Now try to allocate a large block */
    /* This may fail or require new memory from OS even though
       500 * 100 = 50KB is free in scattered chunks */
    char *big = malloc(50000);
    if (big) {
        printf("Large allocation succeeded at %p\n", (void *)big);
        free(big);
    }

    /* Internal fragmentation: malloc(1) actually allocates
       at least 16-32 bytes due to alignment + metadata */
    char *tiny = malloc(1);
    printf("Asked for 1 byte, got block at %p\n", (void *)tiny);
    /* Real usable size is often 16+ bytes */

    /* Clean up */
    free(tiny);
    for (int i = 1; i < N; i += 2) {
        free(ptrs[i]);
    }

    return 0;
}

