#define N 2048
static int matrix[N][N];

/* BAD: Column-major traversal (cache-unfriendly) */
long sum_column_major(void) {
    long sum = 0;
    for (int j = 0; j < N; j++)       /* outer loop over columns */
        for (int i = 0; i < N; i++)   /* inner loop over rows */
            sum += matrix[i][j];      /* stride = N * sizeof(int) */
    return sum;
}

/* GOOD: Row-major traversal (cache-friendly) */
long sum_row_major(void) {
    long sum = 0;
    for (int i = 0; i < N; i++)       /* outer loop over rows */
        for (int j = 0; j < N; j++)   /* inner loop over columns */
            sum += matrix[i][j];      /* stride = sizeof(int) */
    return sum;
}

/* Struct of Arrays (SoA) -- good when accessing one field at a time */
struct particles_soa {
    float x[1000];
    float y[1000];
    float z[1000];
    float mass[1000];
};

/* Array of Structs (AoS) -- good when accessing all fields of one item */
struct particle_aos {
    float x, y, z, mass;
};
struct particle_aos particles[1000];

int main(void) {
    /* Initialize */
    for (int i = 0; i < N; i++)
        for (int j = 0; j < N; j++)
            matrix[i][j] = 1;

    clock_t start, end;

    start = clock();
    long s1 = sum_row_major();
    end = clock();
    printf("Row-major:    %ld (%.3f ms)\n", s1,
           1000.0 * (end - start) / CLOCKS_PER_SEC);

    start = clock();
    long s2 = sum_column_major();
    end = clock();
    printf("Column-major: %ld (%.3f ms)\n", s2,
           1000.0 * (end - start) / CLOCKS_PER_SEC);
    /* Row-major is typically 3-10x faster for large N */

    return 0;
}

