#include <stdio.h>
#include <unistd.h>
#include <stdint.h>

int main(void) {
    /* Get current program break */
    void *initial_brk = sbrk(0);
    printf("Initial program break: %p\n", initial_brk);

    /* Extend heap by 4096 bytes */
    void *old_brk = sbrk(4096);
    if (old_brk == (void *)-1) {
        perror("sbrk");
        return 1;
    }
    printf("Old break: %p\n", old_brk);
    printf("New break: %p\n", sbrk(0));
    printf("Difference: %td bytes\n",
           (char *)sbrk(0) - (char *)old_brk);

    /* Use the allocated memory */
    int *arr = (int *)old_brk;
    for (int i = 0; i < 100; i++) {
        arr[i] = i * i;
    }
    printf("arr[10] = %d\n", arr[10]); /* 100 */

    /* Shrink heap back (return memory) */
    brk(initial_brk);
    printf("Break restored to: %p\n", sbrk(0));

    /* WARNING: Do NOT mix sbrk() with malloc()! */
    /* malloc uses sbrk internally -- direct sbrk calls
       corrupt malloc's data structures */

    return 0;
}

